<script>
import { useLanguage } from '../../composables/useLanguage';

export default {
	props: ['project'],
	setup() {
		const { t } = useLanguage();
		return { t };
	},
	methods: {
		formatDate(dateString) {
			if (!dateString) return '';
			const date = new Date(dateString);
			return date.toLocaleDateString('zh-CN', {
				year: 'numeric',
				month: 'long'
			});
		}
	}
};
</script>

